form:Form.form:Scripts:
		function ONLOAD()
{
	if (Ctrl('main').GetMode() == 'NEW')
		return;

	var ult = 0;
	if (Ctrl('LIST'))
	{
		if (Ctrl('LIST').GetXValue() == Ctrl('LIST').GetAttrValue(Ctrl('LIST').TotalRowsCount()-1, 'id'))
		{
			ult = 1;
		}
	}	
	else
	{
		if (Ctrl('iter-position').GetXValue() == Ctrl('iter-size').GetXValue())
		{
			ult = 1;
		}
	}


	CtrlEnabled('oi_motivo_cambio', false);
	CtrlEnabled('f_egreso', false);
	CtrlEnabled('o_cambio_tper', false);
	CtrlEnabled('DELETE', false);

	if (ult == 1)
	{
		CtrlEnabled('oi_motivo_cambio', true);
		CtrlEnabled('f_egreso', true);
		CtrlEnabled('o_cambio_tper', true);
		CtrlEnabled('DELETE', true);
	}
}
